921	pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
922	    init_with_symlink(args, true)
923	}
924	
925	/// Core init routine with a caller-controlled symlink toggle.
926	///
927	/// - `create_symlink=true` — CLI behavior.
928	/// - `create_symlink=false` — suppresses step 11's side effect
929	///   on `$HOME/.claude/projects/` (test harnesses only).
930	pub(crate) fn init_with_symlink(
931	    args: &InitArgs,
932	    create_symlink: bool,
933	) -> Result<(), Box<dyn std::error::Error>> {
934	    debug!("init: enter");
935	
936	    let cfg = config::load()?;
937	    let plan = plan_init(args, &cfg)?;
938	    let is_dual = plan.scope.is_both();
939	
940	    // --- Preflight ---
941	    info!("Preflight checks...");
942	
943	    debug!("verify jj is installed");
944	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
945	
946	    if plan.provisioner == Provisioner::GhCreate {
947	        debug!("verify gh CLI is installed + authenticated");
948	        run("gh", &["auth", "status"], Path::new("."))
949	            .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
950	    }
951	
952	    if plan.project_dir.exists() {
953	        return Err(format!("'{}' already exists", plan.project_dir.display()).into());
954	    }
955	
956	    match &plan.provisioner {
957	        Provisioner::GhCreate => {
958	            #[allow(clippy::unwrap_used)]
959	            let code_slug = plan.gh_code_slug.as_ref().unwrap(); // OK: GhCreate path always sets gh_code_slug
960	            let (code_owner, code_name) = split_slug(code_slug)?;
961	            if gh_repo_exists(code_owner, code_name)? {
962	                return Err(format!("GitHub repo '{code_slug}' already exists").into());
963	            }
964	            if let Some(session_slug) = plan.gh_session_slug.as_ref() {
965	                let (session_owner, session_name) = split_slug(session_slug)?;
966	                if gh_repo_exists(session_owner, session_name)? {
967	                    return Err(format!("GitHub repo '{session_slug}' already exists").into());
968	                }
969	            }
970	        }
971	        Provisioner::LocalBareInit => {
972	            #[allow(clippy::unwrap_used)]
973	            let code_bare = plan.code_bare_path.as_ref().unwrap(); // OK: LocalBareInit path always sets code_bare_path
974	            if code_bare.exists() {
975	                return Err(format!(
976	                    "bare repo '{}' already exists; refusing to clobber",
977	                    code_bare.display()
978	                )
979	                .into());
980	            }
981	            if let Some(session_bare) = plan.session_bare_path.as_ref()
982	                && session_bare.exists()
983	            {
984	                return Err(format!(
985	                    "bare repo '{}' already exists; refusing to clobber",
986	                    session_bare.display()
987	                )
988	                .into());
989	            }
990	        }
991	        Provisioner::ExternalPreExisting => {
992	            // For path-shaped URLs: the path must exist (caller
993	            // pre-created with `git init --bare`). For scheme-URL
994	            // values we can't preflight cheaply — let git push
995	            // surface failures.
996	            if !is_remote_url(&plan.code_url) {
997	                let p = PathBuf::from(&plan.code_url);
998	                if !p.exists() {
999	                    return Err(format!(
1000	                        "--repo-remote: code path '{}' does not exist — \
1001	                         pre-create with `git init --bare`, or use --repo-local for fixture creation",
1002	                        p.display()
1003	                    )
1004	                    .into());
1005	                }
1006	            }
1007	            if let Some(session_url) = plan.session_url.as_ref()
1008	                && !is_remote_url(session_url)
1009	            {
1010	                let p = PathBuf::from(session_url);
1011	                if !p.exists() {
1012	                    return Err(format!(
1013	                        "--repo-remote: session path '{}' does not exist — \
1014	                         pre-create with `git init --bare`, or use --repo-local for fixture creation",
1015	                        p.display()
1016	                    )
1017	                    .into());
1018	                }
1019	            }
1020	        }
1021	    }
1022	
1023	    let templates = match &args.use_template {
1024	        Some(s) => {
1025	            let (code_t, bot_t) = parse_use_template(s)?;
1026	            if is_dual {
1027	                validate_templates(&code_t, &bot_t)?;
1028	                Some((code_t, Some(bot_t)))
1029	            } else {
1030	                validate_template_one("code", &code_t)?;
1031	                Some((code_t, None))
1032	            }
1033	        }
1034	        None => None,
1035	    };
1036	
1037	    let visibility = if args.private {
1038	        "--private"
1039	    } else {
1040	        "--public"
1041	    };
1042	
1043	    if args.dry_run {
1044	        info!("Dry run — would execute:");
1045	        info!("  1. Create directories: {}", plan.project_dir.display());
1046	        info!(
1047	            "  2. git init + jj git init --colocate on {}",
1048	            if is_dual {
1049	                "both repos"
1050	            } else {
1051	                "the code repo"
1052	            }
1053	        );
1054	        info!(
1055	            "  3. Write .vc-config.toml and .gitignore{}",
1056	            if is_dual {
1057	                " to both repos"
1058	            } else {
1059	                " (code-only layout)"
1060	            }
1061	        );
1062	        match &templates {
1063	            Some((c, b)) => {
1064	                info!("  4. Copy templates (non-hidden) + rewrite README.md first line");
1065	                info!("       code: {}", c.display());
1066	                if let Some(b) = b {
1067	                    info!("       bot:  {}", b.display());
1068	                }
1069	            }
1070	            None => info!("  4. (skipped — no --use-template)"),
1071	        }
1072	        if is_dual {
1073	            info!("  5. jj commit both with placeholder ochids");
1074	            info!("  6. Get both chids, jj describe both with correct ochids");
1075	            info!("  7. Remove jj from both (git clean -xdf)");
1076	        } else {
1077	            info!("  5. jj commit code with 'Initial commit'");
1078	            info!("  6. (skipped — no cross-reference in single-repo)");
1079	            info!("  7. Remove jj (git clean -xdf)");
1080	        }
1081	        match &plan.provisioner {
1082	            Provisioner::GhCreate => {
1083	                if is_dual {
1084	                    info!(
1085	                        "  8. gh repo create {} {visibility}; push to {}",
1086	                        plan.gh_session_slug.as_deref().unwrap_or(""), // OK: dry-run display only
1087	                        plan.session_url.as_deref().unwrap_or(""),     // OK: dry-run display only
1088	                    );
1089	                } else {
1090	                    info!("  8. (skipped — no session side in single-repo)");
1091	                }
1092	                info!(
1093	                    "  9. gh repo create {} {visibility}; push to {}",
1094	                    plan.gh_code_slug.as_deref().unwrap_or(""), // OK: dry-run display only
1095	                    plan.code_url
1096	                );
1097	            }
1098	            Provisioner::LocalBareInit => {
1099	                if is_dual {
1100	                    info!(
1101	                        "  8. git init --bare {}; push to {}",
1102	                        plan.session_bare_path
1103	                            .as_ref()
1104	                            .map(|p| p.display().to_string())
1105	                            .unwrap_or_default(), // OK: dry-run display only
1106	                        plan.session_url.as_deref().unwrap_or(""), // OK: dry-run display only
1107	                    );
1108	                } else {
1109	                    info!("  8. (skipped — no session side in single-repo)");
1110	                }
1111	                info!(
1112	                    "  9. git init --bare {}; push to {}",
1113	                    plan.code_bare_path
1114	                        .as_ref()
1115	                        .map(|p| p.display().to_string())
1116	                        .unwrap_or_default(), // OK: dry-run display only
1117	                    plan.code_url
1118	                );
1119	            }
1120	            Provisioner::ExternalPreExisting => {
1121	                if is_dual {
1122	                    info!(
1123	                        "  8. skip create; push to pre-existing {}",
1124	                        plan.session_url.as_deref().unwrap_or(""), // OK: dry-run display only
1125	                    );
1126	                } else {
1127	                    info!("  8. (skipped — no session side in single-repo)");
1128	                }
1129	                info!("  9. skip create; push to pre-existing {}", plan.code_url);
1130	            }
1131	        }
1132	        info!(
1133	            "  10. jj git init --colocate on {}",
1134	            if is_dual {
1135	                "both repos"
1136	            } else {
1137	                "the code repo"
1138	            }
1139	        );
1140	        if is_dual {
1141	            info!("  11. Create Claude Code symlink");
1142	        } else {
1143	            info!("  11. (skipped — no .claude symlink in single-repo)");
1144	        }
1145	        return Ok(());
1146	    }
1147	
1148	    // Step 1: Create directories. For LocalBareInit also create the
1149	    // parent so the bare-repo init (step 8/9) has a home.
1150	    info!("Step 1: Creating project directories...");
1151	    if let Some(parent) = plan.project_dir.parent() {
1152	        mkdir_p(parent)?;
1153	    }
1154	    mkdir_p(&plan.project_dir)?;
1155	    if let Some(session_dir) = plan.session_dir.as_ref() {
1156	        mkdir_p(session_dir)?;
1157	    }
1158	
1159	    // Step 2: git init + jj init
1160	    info!("Step 2: Initializing repos...");
1161	    debug!("seed project_dir with an empty git repo");
1162	    run("git", &["init"], &plan.project_dir)?;
1163	    debug!("colocate jj atop the git repo so jj + git share .git state");
1164	    run("jj", &["git", "init", "--colocate"], &plan.project_dir)?;
1165	    if let Some(session_dir) = plan.session_dir.as_ref() {
1166	        debug!("seed session_dir with an empty git repo");
1167	        run("git", &["init"], session_dir)?;
1168	        debug!("colocate jj atop the session git repo");
1169	        run("jj", &["git", "init", "--colocate"], session_dir)?;
1170	    }
1171	
1172	    // Step 3: Write config files
1173	    info!("Step 3: Writing config files...");
1174	    if is_dual {
1175	        write_file(&plan.project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
1176	        write_file(&plan.project_dir.join(".gitignore"), GITIGNORE_CODE)?;
1177	    } else {
1178	        write_file(
1179	            &plan.project_dir.join(".vc-config.toml"),
1180	            VC_CONFIG_APP_ONLY,
1181	        )?;
1182	        write_file(&plan.project_dir.join(".gitignore"), GITIGNORE_APP_ONLY)?;
1183	    }
1184	    if let Some(session_dir) = plan.session_dir.as_ref() {
1185	        write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
1186	        write_file(&session_dir.join(".gitignore"), GITIGNORE_SESSION)?;
1187	    }
1188	
1189	    // Step 4: Copy templates (if --use-template)
1190	    if let Some((code_t, bot_t)) = &templates {
1191	        info!("Step 4: Copying templates...");
1192	        info!(
1193	            "  code: {} -> {}",
1194	            code_t.display(),
1195	            plan.project_dir.display()
1196	        );
1197	        copy_template_recursive(code_t, &plan.project_dir)?;
1198	        rewrite_readme_first_line(&plan.project_dir, &plan.name)?;
1199	        if let (Some(bot_t), Some(session_dir), Some(session_name)) = (
1200	            bot_t.as_ref(),
1201	            plan.session_dir.as_ref(),
1202	            plan.session_name.as_ref(),
1203	        ) {
1204	            info!("  bot:  {} -> {}", bot_t.display(), session_dir.display());
1205	            copy_template_recursive(bot_t, session_dir)?;
1206	            rewrite_readme_first_line(session_dir, session_name)?;
1207	        }
1208	    }
1209	
1210	    // Step 5: jj commit
1211	    if is_dual {
1212	        info!("Step 5: Committing both repos with placeholder ochids...");
1213	        #[allow(clippy::unwrap_used)]
1214	        let session_dir = plan.session_dir.as_ref().unwrap(); // OK: is_dual ⇒ session_dir set
1215	        debug!("code side: initial commit with placeholder ochid (rewritten in step 6)");
1216	        run(
1217	            "jj",
1218	            &["commit", "-m", "Initial commit\n\nochid: /none"],
1219	            &plan.project_dir,
1220	        )?;
1221	        debug!("session side: initial commit with placeholder ochid (rewritten in step 6)");
1222	        run(
1223	            "jj",
1224	            &["commit", "-m", "Initial commit\n\nochid: /none"],
1225	            session_dir,
1226	        )?;
1227	    } else {
1228	        info!("Step 5: Committing code...");
1229	        debug!("code side: initial commit (no ochid in single-repo)");
1230	        run("jj", &["commit", "-m", "Initial commit"], &plan.project_dir)?;
1231	    }
1232	
1233	    // Step 6: ochid cross-references (dual only)
1234	    if is_dual {
1235	        info!("Step 6: Setting ochid cross-references...");
1236	        #[allow(clippy::unwrap_used)]
1237	        let session_dir = plan.session_dir.as_ref().unwrap(); // OK: is_dual ⇒ session_dir set
1238	        let code_chid = jj_chid("@-", &plan.project_dir)?;
1239	        let session_chid = jj_chid("@-", session_dir)?;
1240	
1241	        let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
1242	        let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
1243	        debug!("code side: rewrite initial commit's ochid to point at session chid");
1244	        run(
1245	            "jj",
1246	            &["describe", "@-", "-m", &code_desc],
1247	            &plan.project_dir,
1248	        )?;
1249	        debug!("session side: rewrite initial commit's ochid to point at code chid");
1250	        run("jj", &["describe", "@-", "-m", &session_desc], session_dir)?;
1251	
1252	        debug!("surface post-describe git hashes for the debug log");
1253	        let hash = run("git", &["rev-parse", "HEAD"], &plan.project_dir)?;
1254	        debug!("code repo: chid={code_chid} hash={hash}");
1255	        let hash = run("git", &["rev-parse", "HEAD"], session_dir)?;
1256	        debug!(".claude:   chid={session_chid} hash={hash}");
1257	    } else {
1258	        info!("Step 6: (skipped — no cross-reference in single-repo)");
1259	        let code_chid = jj_chid("@-", &plan.project_dir)?;
1260	        let hash = run("git", &["rev-parse", "HEAD"], &plan.project_dir)?;
1261	        debug!("code repo: chid={code_chid} hash={hash}");
1262	    }
1263	
1264	    // Step 7: Set bookmarks (creates git branches), then remove jj
1265	    info!("Step 7: Setting bookmarks and removing jj...");
1266	    debug!("place code-side main bookmark at the initial commit");
1267	    run(
1268	        "jj",
1269	        &["bookmark", "set", "main", "-r", "@-"],
1270	        &plan.project_dir,
1271	    )?;
1272	    if let Some(session_dir) = plan.session_dir.as_ref() {
1273	        debug!("place session-side main bookmark at the initial commit");
1274	        run("jj", &["bookmark", "set", "main", "-r", "@-"], session_dir)?;
1275	        debug!("strip jj state from session side before its git push");
1276	        run("git", &["clean", "-xdf"], session_dir)?;
1277	        debug!("strip jj state from code side, preserving nested .claude/");
1278	        run(
1279	            "git",
1280	            &["clean", "-xdf", "--exclude", ".claude"],
1281	            &plan.project_dir,
1282	        )?;
1283	        debug!("re-attach session HEAD to main after clean");
1284	        run("git", &["checkout", "main"], session_dir)?;
1285	    } else {
1286	        debug!("strip jj state from code side (no .claude in single-repo)");
1287	        run("git", &["clean", "-xdf"], &plan.project_dir)?;
1288	    }
1289	    debug!("re-attach code HEAD to main after clean");
1290	    run("git", &["checkout", "main"], &plan.project_dir)?;
1291	
1292	    // Steps 8/9: provision remotes and push.
1293	    if let Some(session_dir) = plan.session_dir.as_ref() {
1294	        #[allow(clippy::unwrap_used)]
1295	        let session_url = plan.session_url.as_deref().unwrap(); // OK: is_dual ⇒ session_url set
1296	        run_remote_step(
1297	            "Step 8",
1298	            "session",
1299	            &plan,
1300	            session_url,
1301	            plan.gh_session_slug.as_deref(),
1302	            plan.session_bare_path.as_deref(),
1303	            visibility,
1304	            session_dir,
1305	            args,
1306	        )?;
1307	    } else {
1308	        info!("Step 8: (skipped — no session side in single-repo)");
1309	    }
1310	    run_remote_step(
1311	        "Step 9",
1312	        "code",
1313	        &plan,
1314	        &plan.code_url,
1315	        plan.gh_code_slug.as_deref(),
1316	        plan.code_bare_path.as_deref(),
1317	        visibility,
1318	        &plan.project_dir,
1319	        args,
1320	    )?;
1321	
1322	    // Step 10: Re-initialize jj
1323	    info!(
1324	        "Step 10: Re-initializing jj on {}...",
1325	        if is_dual {
1326	            "both repos"
1327	        } else {
1328	            "the code repo"
1329	        }
1330	    );
1331	    debug!("re-colocate jj atop the now-remote-linked code repo");
1332	    run(
1333	        "jj",
1334	        &["--quiet", "git", "init", "--colocate"],
1335	        &plan.project_dir,
1336	    )?;
1337	    debug!("restore code-side main bookmark after re-init");
1338	    run(
1339	        "jj",
1340	        &["bookmark", "set", "main", "-r", "@-"],
1341	        &plan.project_dir,
1342	    )?;
1343	    debug!("enable jj tracking of code-side main against origin");
1344	    run(
1345	        "jj",
1346	        &["bookmark", "track", "main", "--remote=origin"],
1347	        &plan.project_dir,
1348	    )?;
1349	    crate::common::verify_tracking(&plan.project_dir, "main")?;
1350	    let code_chid_final = jj_chid("@-", &plan.project_dir)?;
1351	
1352	    let session_chid_final = if let Some(session_dir) = plan.session_dir.as_ref() {
1353	        debug!("re-colocate jj atop the now-remote-linked session repo");
1354	        run("jj", &["--quiet", "git", "init", "--colocate"], session_dir)?;
1355	        debug!("restore session-side main bookmark after re-init");
1356	        run("jj", &["bookmark", "set", "main", "-r", "@-"], session_dir)?;
1357	        debug!("enable jj tracking of session-side main against origin");
1358	        run(
1359	            "jj",
1360	            &["bookmark", "track", "main", "--remote=origin"],
1361	            session_dir,
1362	        )?;
1363	        crate::common::verify_tracking(session_dir, "main")?;
1364	        Some(jj_chid("@-", session_dir)?)
1365	    } else {
1366	        None
1367	    };
1368	
1369	    // Step 11: Create Claude Code symlink (dual only; opt-out for tests)
1370	    let sl_opt = if is_dual && create_symlink {
1371	        info!("Step 11: Creating Claude Code symlink...");
1372	        Some(symlink::install(&plan.project_dir)?)
1373	    } else if !is_dual {
1374	        info!("Step 11: (skipped — no .claude symlink in single-repo)");
