        )?;
        write_file(&plan.project_dir.join(".gitignore"), GITIGNORE_APP_ONLY)?;
    }
    if let Some(session_dir) = plan.session_dir.as_ref() {
        write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
