    run("jj", &["git", "init", "--colocate"], session_dir)?;

    // Step 3: Write config files (CODE/SESSION shapes)
    info!("Step 3: Writing config files...");
    write_file(&plan.project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
