/// Initial-commit ochid policy used by `init_one_create`.
///
/// - `None` — POR: plain `Initial commit` message.
/// - `Placeholder` — Dual: `Initial commit\n\nochid: /none`,
///   rewritten via cross-ref `jj describe` once both sides have
///   committed and their chids are known.
#[derive(Clone, Copy, Debug)]
enum OchidStrategy {
    None,
    Placeholder,
}

/// Per-side create primitive: steps 1-5 (mkdir, git/jj init,
/// configs, optional template, initial commit) on `target`.
/// Returns the chid of the new initial commit (`jj @-`).
///
/// - `side_label` — narration tag (`"code"`, `"bot"`); appears in
///   step `info!()` lines.
/// - `config` / `gitignore` — file contents written at
///   `target/.vc-config.toml` and `target/.gitignore`. Caller
///   picks the variant (`VC_CONFIG_APP_ONLY` / `VC_CONFIG_CODE` /
///   `VC_CONFIG_SESSION`, etc.).
/// - `template` — optional source dir. When present, copied
///   recursively (non-hidden only) and any `README.md`'s first
///   line is rewritten to `# <name>`.
/// - `name` — repo name used by the README rewrite.
/// - `ochid_strategy` — initial-commit message policy.
///
/// Per-side narration: `info!()` is emitted once per call rather
/// than once per step across sides — dual orchestrators get two
/// narration passes (code, then bot) instead of one interleaved.
#[allow(clippy::too_many_arguments)]
fn init_one_create(
    target: &Path,
    side_label: &str,
    config: &str,
    gitignore: &str,
    template: Option<&Path>,
    name: &str,
    ochid_strategy: OchidStrategy,
) -> Result<String, Box<dyn std::error::Error>> {
    info!(
        "Step 1: Creating {side_label} directory at {}",
        target.display()
    );
    if let Some(parent) = target.parent() {
        mkdir_p(parent)?;
    }
    mkdir_p(target)?;

    info!("Step 2: Initializing {side_label} repo (git + jj)...");
    debug!("seed {side_label} dir with an empty git repo");
    run("git", &["init"], target)?;
    debug!("colocate jj atop the {side_label} git repo");
    run("jj", &["git", "init", "--colocate"], target)?;

    info!("Step 3: Writing {side_label} config files...");
    write_file(&target.join(".vc-config.toml"), config)?;
    write_file(&target.join(".gitignore"), gitignore)?;

    match template {
        Some(t) => {
            info!(
                "Step 4: Copying {side_label} template: {} -> {}",
                t.display(),
                target.display()
            );
            copy_template_recursive(t, target)?;
            rewrite_readme_first_line(target, name)?;
        }
        None => {
            info!("Step 4: (skipped — no {side_label} template)");
        }
    }

    let msg = match ochid_strategy {
        OchidStrategy::None => "Initial commit",
        OchidStrategy::Placeholder => "Initial commit\n\nochid: /none",
    };
    info!("Step 5: Committing {side_label}...");
    debug!("{side_label} side: jj commit (ochid_strategy={ochid_strategy:?})");
    run("jj", &["commit", "-m", msg], target)?;

    let chid = jj_chid("@-", target)?;
    debug!("{side_label} initial chid = {chid}");
    Ok(chid)
}

/// Create-from-empty primitive for `--scope=por` (single repo).
///
/// Composes:
/// - `init_one_create` (steps 1-5, `OchidStrategy::None`).
/// - Step 7: bookmark + `git clean -xdf`.
/// - Step 9: provision remote + push.
/// - Step 10: re-init jj + bookmark tracking.
///
/// No cross-reference ochid, no session repo, no symlink.
fn init_one(
    args: &InitArgs,
    plan: &InitPlan,
    templates: Option<(PathBuf, Option<PathBuf>)>,
    visibility: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let code_template = templates.as_ref().map(|(c, _)| c.as_path());

    // Steps 1-5 via the per-side primitive.
    let code_chid = init_one_create(
        &plan.project_dir,
        "code",
        VC_CONFIG_APP_ONLY,
        GITIGNORE_APP_ONLY,
        code_template,
        &plan.name,
        OchidStrategy::None,
    )?;

    // Step 6: skipped — no cross-reference in single-repo
    info!("Step 6: (skipped — no cross-reference in single-repo)");
    let hash = run("git", &["rev-parse", "HEAD"], &plan.project_dir)?;
    debug!("code repo: chid={code_chid} hash={hash}");

    // Step 7: Set bookmark (creates git branch), then remove jj
    info!("Step 7: Setting bookmarks and removing jj...");
    debug!("place code-side main bookmark at the initial commit");
    run(
        "jj",
        &["bookmark", "set", "main", "-r", "@-"],
        &plan.project_dir,
    )?;
    debug!("strip jj state from code side (no .claude in single-repo)");
    run("git", &["clean", "-xdf"], &plan.project_dir)?;
    debug!("re-attach code HEAD to main after clean");
    run("git", &["checkout", "main"], &plan.project_dir)?;

    // Step 8: skipped — no session side in single-repo
    info!("Step 8: (skipped — no session side in single-repo)");

    // Step 9: provision remote and push code
    run_remote_step(
        "Step 9",
        "code",
        plan,
        &plan.code_url,
        plan.gh_code_slug.as_deref(),
        plan.code_bare_path.as_deref(),
        visibility,
        &plan.project_dir,
        args,
    )?;

    // Step 10: Re-initialize jj
    info!("Step 10: Re-initializing jj on the code repo...");
    debug!("re-colocate jj atop the now-remote-linked code repo");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &plan.project_dir,
    )?;
    debug!("restore code-side main bookmark after re-init");
    run(
        "jj",
        &["bookmark", "set", "main", "-r", "@-"],
        &plan.project_dir,
    )?;
    debug!("enable jj tracking of code-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &plan.project_dir,
    )?;
    crate::common::verify_tracking(&plan.project_dir, "main")?;
    let code_chid_final = jj_chid("@-", &plan.project_dir)?;

    // Step 11: skipped — no .claude symlink in single-repo
    info!("Step 11: (skipped — no .claude symlink in single-repo)");

    info!("");
    info!("Done! Project created at {}", plan.project_dir.display());
    info!(
        "  Code repo:    {}  (chid={code_chid_final})",
        plan.code_url
    );

    debug!("init: exit");
    Ok(())
}

/// Create-from-empty orchestrator for `--scope=code,bot` (dual).
///
/// Composes:
/// - `init_one_create` for code side (`OchidStrategy::Placeholder`).
/// - `init_one_create` for session side (`OchidStrategy::Placeholder`).
/// - Step 6: cross-reference ochids using both returned chids.
/// - Step 7: bookmark + clean both (code-side clean preserves
///   `.claude/`).
/// - Steps 8/9: provision remotes + push session, then code.
/// - Step 10: re-init + bookmark tracking on both.
/// - Step 11: install symlink (when `create_symlink`).
fn init_dual(
    args: &InitArgs,
    plan: &InitPlan,
    templates: Option<(PathBuf, Option<PathBuf>)>,
    visibility: &str,
    create_symlink: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    #[allow(clippy::unwrap_used)]
    let session_dir = plan.session_dir.as_ref().unwrap(); // OK: scope=code,bot ⇒ session_dir set
    #[allow(clippy::unwrap_used)]
    let session_name = plan.session_name.as_ref().unwrap(); // OK: scope=code,bot ⇒ session_name set
    #[allow(clippy::unwrap_used)]
    let session_url = plan.session_url.as_deref().unwrap(); // OK: scope=code,bot ⇒ session_url set

    let (code_template, bot_template) = match templates.as_ref() {
        Some((c, b)) => (Some(c.as_path()), b.as_deref()),
        None => (None, None),
    };

    // Steps 1-5 per side: code first, then bot.
    let code_chid = init_one_create(
        &plan.project_dir,
        "code",
        VC_CONFIG_CODE,
        GITIGNORE_CODE,
        code_template,
        &plan.name,
        OchidStrategy::Placeholder,
    )?;
    let session_chid = init_one_create(
        session_dir,
        "bot",
        VC_CONFIG_SESSION,
        GITIGNORE_SESSION,
        bot_template,
        session_name,
        OchidStrategy::Placeholder,
    )?;

    // Step 6: ochid cross-references (rewrites both placeholders)
    info!("Step 6: Setting ochid cross-references...");
    let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
    let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
    debug!("code side: rewrite initial commit's ochid to point at session chid");
    run(
        "jj",
        &["describe", "@-", "-m", &code_desc],
        &plan.project_dir,
    )?;
    debug!("session side: rewrite initial commit's ochid to point at code chid");
    run("jj", &["describe", "@-", "-m", &session_desc], session_dir)?;

    debug!("surface post-describe git hashes for the debug log");
    let hash = run("git", &["rev-parse", "HEAD"], &plan.project_dir)?;
    debug!("code repo: chid={code_chid} hash={hash}");
    let hash = run("git", &["rev-parse", "HEAD"], session_dir)?;
    debug!(".claude:   chid={session_chid} hash={hash}");

    // Step 7: Set bookmarks, remove jj (code-side clean preserves .claude/)
    info!("Step 7: Setting bookmarks and removing jj...");
    debug!("place code-side main bookmark at the initial commit");
    run(
        "jj",
        &["bookmark", "set", "main", "-r", "@-"],
        &plan.project_dir,
    )?;
    debug!("place session-side main bookmark at the initial commit");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], session_dir)?;
    debug!("strip jj state from session side before its git push");
    run("git", &["clean", "-xdf"], session_dir)?;
    debug!("strip jj state from code side, preserving nested .claude/");
    run(
        "git",
        &["clean", "-xdf", "--exclude", ".claude"],
        &plan.project_dir,
    )?;
    debug!("re-attach session HEAD to main after clean");
    run("git", &["checkout", "main"], session_dir)?;
    debug!("re-attach code HEAD to main after clean");
    run("git", &["checkout", "main"], &plan.project_dir)?;

    // Steps 8/9: provision remotes and push.
    run_remote_step(
        "Step 8",
        "session",
        plan,
        session_url,
        plan.gh_session_slug.as_deref(),
        plan.session_bare_path.as_deref(),
        visibility,
        session_dir,
        args,
    )?;
    run_remote_step(
        "Step 9",
        "code",
        plan,
        &plan.code_url,
        plan.gh_code_slug.as_deref(),
        plan.code_bare_path.as_deref(),
        visibility,
        &plan.project_dir,
        args,
    )?;

    // Step 10: Re-initialize jj on both repos
    info!("Step 10: Re-initializing jj on both repos...");
    debug!("re-colocate jj atop the now-remote-linked code repo");
    run(
        "jj",
        &["--quiet", "git", "init", "--colocate"],
        &plan.project_dir,
    )?;
    debug!("restore code-side main bookmark after re-init");
    run(
        "jj",
        &["bookmark", "set", "main", "-r", "@-"],
        &plan.project_dir,
    )?;
    debug!("enable jj tracking of code-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        &plan.project_dir,
    )?;
    crate::common::verify_tracking(&plan.project_dir, "main")?;
    let code_chid_final = jj_chid("@-", &plan.project_dir)?;

    debug!("re-colocate jj atop the now-remote-linked session repo");
    run("jj", &["--quiet", "git", "init", "--colocate"], session_dir)?;
    debug!("restore session-side main bookmark after re-init");
    run("jj", &["bookmark", "set", "main", "-r", "@-"], session_dir)?;
    debug!("enable jj tracking of session-side main against origin");
    run(
        "jj",
        &["bookmark", "track", "main", "--remote=origin"],
        session_dir,
    )?;
    crate::common::verify_tracking(session_dir, "main")?;
    let session_chid_final = jj_chid("@-", session_dir)?;

    // Step 11: Create Claude Code symlink (opt-out for tests)
    let sl_opt = if create_symlink {
        info!("Step 11: Creating Claude Code symlink...");
        Some(symlink::install(&plan.project_dir)?)
    } else {
        info!("Step 11: (skipped — symlink disabled by caller)");
        None
    };

    info!("");
    info!("Done! Project created at {}", plan.project_dir.display());
    info!(
        "  Code repo:    {}  (chid={code_chid_final})",
        plan.code_url
    );
    info!("  Session repo: {session_url}  (chid={session_chid_final})");
    if let Some(sl) = sl_opt.as_ref() {
        info!(
            "  Symlink:      {} -> {}",
            sl.symlink_path.display(),
            sl.abs_target.display()
        );
    }

    debug!("init: exit");
    Ok(())
}

