    // ---------- init_one_create direct tests ----------

    /// Direct call with `OchidStrategy::None` produces the POR-shape
    /// state through step 5: APP_ONLY config, gitignore without
    /// `/.claude`, plain `Initial commit` message.
    #[test]
    fn init_one_create_strategy_none_writes_plain_commit() {
        let base = crate::test_helpers::unique_base("init-one-create-none");
        let target = base.join("work");
        std::fs::create_dir_all(&base).expect("mkdir base");

        let chid = init_one_create(
            &target,
            "code",
            VC_CONFIG_APP_ONLY,
            GITIGNORE_APP_ONLY,
            None,
            "scratch",
            OchidStrategy::None,
        )
        .expect("init_one_create with strategy None");

        assert!(!chid.is_empty(), "chid returned");
        assert!(target.join(".jj").exists(), "jj initialized");
        assert!(target.join(".git").exists(), "git initialized");

        let cfg =
            std::fs::read_to_string(target.join(".vc-config.toml")).expect("read config");
        assert!(cfg.contains("path = \"/\""));
        assert!(!cfg.contains("other-repo"));

        let log = run("git", &["log", "-1", "--format=%B"], &target).expect("git log");
        assert_eq!(
            log.trim(),
            "Initial commit",
            "OchidStrategy::None uses a plain message"
        );

        let _ = std::fs::remove_dir_all(&base);
    }

    /// Direct call with `OchidStrategy::Placeholder` writes the
    /// `ochid: /none` placeholder in the initial commit message —
    /// what dual mode lands before the cross-ref rewrite in step 6.
    #[test]
    fn init_one_create_strategy_placeholder_writes_ochid_none() {
        let base = crate::test_helpers::unique_base("init-one-create-placeholder");
        let target = base.join("work");
        std::fs::create_dir_all(&base).expect("mkdir base");

        let _chid = init_one_create(
            &target,
            "code",
            VC_CONFIG_CODE,
            GITIGNORE_CODE,
            None,
            "scratch",
            OchidStrategy::Placeholder,
        )
        .expect("init_one_create with strategy Placeholder");

        let cfg =
            std::fs::read_to_string(target.join(".vc-config.toml")).expect("read config");
        assert!(cfg.contains("other-repo = \".claude\""));

        let log = run("git", &["log", "-1", "--format=%B"], &target).expect("git log");
        assert!(log.contains("Initial commit"));
        assert!(
            log.contains("ochid: /none"),
            "OchidStrategy::Placeholder leaves a placeholder ochid trailer"
        );

        let _ = std::fs::remove_dir_all(&base);
    }
}

