1	//! Parsing and derivation helpers for repository URLs and targets.
2	//!
3	//! Single source of truth for the positional `<TARGET>` forms
4	//! that `init` and `clone` accept (URL, owner/name shorthand,
5	//! path) and for the URL-derivation helpers shared between them.
6	//!
7	//! Lifted from `clone.rs` / `init.rs` in 0.41.1-1; consumers
8	//! migrate to `parse_target` in 0.41.1-2 (clone) and 0.41.1-3
9	//! (init).
10	
11	use std::path::PathBuf;
12	
13	/// A parsed positional `<TARGET>` argument to `init` or `clone`.
14	///
15	/// - `Url` — full git URL (`scheme://...` or SSH `user@host:path`).
16	/// - `OwnerName(owner, name)` — `owner/name` shorthand;
17	///   resolves to `git@github.com:owner/name.git`.
18	/// - `Path` — local path with explicit prefix
19	///   (`./`, `../`, `/`, `~/`, or bare `~`). Path text is preserved
20	///   literally; tilde expansion is the consumer's responsibility.
21	/// - `BareName` — a bare alphanumeric (no `/`, `:`, or path
22	///   prefix). Init resolves it via the user-config remote chain;
23	///   clone errors on it (no config-driven default).
24	#[derive(Debug, PartialEq, Eq, Clone)]
25	pub enum Target {
26	    Url(String),
27	    OwnerName(String, String),
28	    Path(PathBuf),
29	    BareName(String),
30	}
31	
32	/// Parse a positional `<TARGET>` argument into one of the four
33	/// `Target` variants.
34	///
35	/// Detection order (path forms first, then URL, then shorthand,
36	/// then bare NAME):
37	///
38	/// - Path forms: bare `.`, `..`, or `~`; or starts with `./`,
39	///   `../`, `/`, or `~/`. `.` and `..` are POSIX cwd/parent and
40	///   are unambiguous; the consumer resolves them to a real
41	///   directory name via `canonicalize` + `file_name`.
42	/// - URL: contains `://`, or SSH-style `user@host:path` (an `@`
43	///   followed somewhere by `:`).
44	/// - `owner/name` shorthand: exactly one `/`, both sides non-empty,
45	///   no path or URL indicators.
46	/// - Bare NAME: no `/`, no `:`, no URL/path indicators. Init
47	///   resolves it via the user-config remote chain (repo created
48	///   at `cwd/<NAME>`); clone errors on it (no config).
49	///
50	/// Errors only on empty input or syntactic garbage that fits
51	/// none of the above (e.g. `owner/name/extra`).
52	pub fn parse_target(s: &str) -> Result<Target, String> {
53	    if s.is_empty() {
54	        return Err("empty target".into());
55	    }
56	
57	    if s == "."
58	        || s == ".."
59	        || s == "~"
60	        || s.starts_with("./")
61	        || s.starts_with("../")
62	        || s.starts_with('/')
63	        || s.starts_with("~/")
64	    {
65	        return Ok(Target::Path(PathBuf::from(s)));
66	    }
67	
68	    if s.contains("://") {
69	        return Ok(Target::Url(s.to_string()));
70	    }
71	    if let Some(at) = s.find('@')
72	        && s[at + 1..].contains(':')
73	    {
74	        return Ok(Target::Url(s.to_string()));
75	    }
76	
77	    if s.matches('/').count() == 1
78	        && let Some((owner, name)) = s.split_once('/')
79	        && !owner.is_empty()
80	        && !name.is_empty()
81	        && !owner.contains(':')
82	        && !name.contains(':')
83	    {
84	        return Ok(Target::OwnerName(owner.to_string(), name.to_string()));
85	    }
86	
87	    // Bare NAME: no slash, no colon, no URL pattern. Init expands
88	    // via config; clone rejects.
89	    if !s.contains('/') && !s.contains(':') {
90	        return Ok(Target::BareName(s.to_string()));
91	    }
92	
93	    // Catch-all. If it looks like an SSH scp-like form missing the
94	    // `git@` prefix (host:owner/name), suggest the canonical form
95	    // — easy mistake to make and the resulting "did you mean…?"
96	    // is concrete enough to fix with one re-type.
97	    if let Some(colon) = s.find(':')
98	        && colon > 0
99	        && !s[..colon].contains('/')
100	        && s[colon + 1..].contains('/')
101	        && !s.contains('@')
102	    {
103	        return Err(format!(
104	            "'{s}' is not a recognized target — looks like an SSH URL missing the 'git@' prefix; did you mean 'git@{s}'?"
105	        ));
106	    }
107	
108	    Err(format!(
109	        "'{s}' is not a recognized target — expected URL, owner/name shorthand, path prefix (./X, ../X, /X, ~/X, ~), or bare NAME"
110	    ))
111	}
112	
113	/// Derive the project name from a repo URL or `owner/name` shorthand.
114	///
115	/// - Strips trailing `.git`.
116	/// - Returns the last segment after the rightmost `/` or `:`.
117	/// - Errors when the resulting name would be empty.
118	pub fn derive_name(repo: &str) -> Result<String, Box<dyn std::error::Error>> {
119	    let stem = repo.strip_suffix(".git").unwrap_or(repo); // OK: .git suffix is optional
120	    let last = stem.rsplit(['/', ':']).next().unwrap_or(""); // OK: rsplit always yields at least one element
121	    if last.is_empty() {
122	        return Err(format!("cannot derive project name from '{repo}'").into());
123	    }
124	    Ok(last.to_string())
125	}
126	
127	/// Resolve a repo argument to a git clone URL.
128	///
129	/// - `owner/name` (single `/`, no `:` or scheme) →
130	///   `git@github.com:owner/name.git`.
131	/// - Anything else is passed through as-is (already a URL).
132	pub fn resolve_url(repo: &str) -> String {
133	    if repo.contains("://") || repo.contains('@') {
134	        return repo.to_string();
135	    }
136	    if repo.matches('/').count() == 1 && !repo.contains(':') {
137	        return format!("git@github.com:{repo}.git");
138	    }
139	    repo.to_string()
140	}
141	
142	/// Derive the session repo URL from a code repo URL.
143	///
144	/// - With trailing `.git`: insert `.claude` before it
145	///   (`foo.git` → `foo.claude.git`).
146	/// - Without `.git`: append `.claude` (`foo` → `foo.claude`).
147	pub fn derive_session_url(code_url: &str) -> String {
148	    match code_url.strip_suffix(".git") {
149	        Some(stem) => format!("{stem}.claude.git"),
150	        None => format!("{code_url}.claude"),
151	    }
152	}
