///   (`foo.git` → `foo.claude.git`).
/// - Without `.git`: append `.claude` (`foo` → `foo.claude`).
pub fn derive_session_url(code_url: &str) -> String {
    match code_url.strip_suffix(".git") {
        Some(stem) => format!("{stem}.claude.git"),
        None => format!("{code_url}.claude"),
    }
}

