/// Initial-commit ochid policy used by `init_one_create`.
///
/// - `None` — POR: plain `Initial commit` message.
/// - `Placeholder` — Dual: `Initial commit\n\nochid: /none`,
///   rewritten via cross-ref `jj describe` once both sides have
///   committed and their chids are known.
#[derive(Clone, Copy, Debug)]
enum OchidStrategy {
    None,
    Placeholder,
}

/// Per-side create primitive: steps 1-5 (mkdir, git/jj init,
/// configs, optional template, initial commit) on `target`.
/// Returns the chid of the new initial commit (`jj @-`).
///
/// - `side_label` — narration tag (`"code"`, `"bot"`); appears in
///   step `info!()` lines.
/// - `config` / `gitignore` — file contents written at
///   `target/.vc-config.toml` and `target/.gitignore`. Caller
///   picks the variant (`VC_CONFIG_APP_ONLY` / `VC_CONFIG_CODE` /
///   `VC_CONFIG_SESSION`, etc.).
/// - `template` — optional source dir. When present, copied
///   recursively (non-hidden only) and any `README.md`'s first
///   line is rewritten to `# <name>`.
/// - `name` — repo name used by the README rewrite.
/// - `ochid_strategy` — initial-commit message policy.
///
/// Per-side narration: `info!()` is emitted once per call rather
/// than once per step across sides — dual orchestrators get two
/// narration passes (code, then bot) instead of one interleaved.
#[allow(clippy::too_many_arguments)]
fn init_one_create(
    target: &Path,
    side_label: &str,
    config: &str,
    gitignore: &str,
    template: Option<&Path>,
    name: &str,
    ochid_strategy: OchidStrategy,
) -> Result<String, Box<dyn std::error::Error>> {
    info!(
        "Step 1: Creating {side_label} directory at {}",
        target.display()
    );
    if let Some(parent) = target.parent() {
        mkdir_p(parent)?;
    }
    mkdir_p(target)?;

    info!("Step 2: Initializing {side_label} repo (git + jj)...");
    debug!("seed {side_label} dir with an empty git repo");
    run("git", &["init"], target)?;
    debug!("colocate jj atop the {side_label} git repo");
    run("jj", &["git", "init", "--colocate"], target)?;

    info!("Step 3: Writing {side_label} config files...");
    write_file(&target.join(".vc-config.toml"), config)?;
    write_file(&target.join(".gitignore"), gitignore)?;

    match template {
        Some(t) => {
            info!(
                "Step 4: Copying {side_label} template: {} -> {}",
                t.display(),
                target.display()
            );
            copy_template_recursive(t, target)?;
            rewrite_readme_first_line(target, name)?;
        }
        None => {
            info!("Step 4: (skipped — no {side_label} template)");
        }
    }

    let msg = match ochid_strategy {
        OchidStrategy::None => "Initial commit",
        OchidStrategy::Placeholder => "Initial commit\n\nochid: /none",
    };
    info!("Step 5: Committing {side_label}...");
    debug!("{side_label} side: jj commit (ochid_strategy={ochid_strategy:?})");
    run("jj", &["commit", "-m", msg], target)?;

    let chid = jj_chid("@-", target)?;
    debug!("{side_label} initial chid = {chid}");
    Ok(chid)
}

