    debug!("{info_label} side: jj commit (ochid_strategy={ochid_strategy:?})");
    run("jj", &["commit", "-m", msg], target)?;

    let chid = jj_chid("@-", target)?;
    debug!("{info_label} initial chid = {chid}");
    Ok(chid)
}

